#include <iostream>using namespace std;int s[4000000];int cnt=0;void ins(int x){	int p=0;	while(p<cnt&&s[p]<x) p++;	for(int i=cnt;i>p;i--)		s[i]=s[i-1];	s[p]=x;	cnt++;}void del(int k){	int p=k-1;	for(int i=p;i<cnt-1;i++)		s[i]=s[i+1];	cnt--;}int main(){	int n,q;	cin>>n>>q;	cnt=0;	for(int i=1;i<=n;++i)	{		int x;		cin>>x;		ins(x);	}	while(q--)	{		int k;		cin>>k;		if(k>0)			ins(k);		else			del(-k);	}	if(cnt>0)		cout<<s[0]<<endl;	else		cout<<0<<endl;	return 0;}